/*eslint no-unused-vars: "off"*/
<template>
  <div>
          <v-row>
            <v-col md="2">
              <v-container>
              Scanner le sous réseau du tap
              </v-container>
            </v-col>
            <v-col md="1" class="ml-n10">
              <v-select
                :items="taps"
                class="maxWidth"
                v-model="currentTap"
                dense
              ></v-select>
            </v-col>
            <v-col md="1">
              <v-btn @click="scanTap()" color="grey lighten-3" small class="mr-1" >
                <v-icon>
                  mdi-magnify-scan
                </v-icon>
              </v-btn>
            </v-col>
          </v-row>
        <v-data-table
          :headers="headers"
          :items=list
        >
        <template v-slot:item="{ item }" >
            <tr>
              <td>{{item.ip}}</td>
              <td v-if="item.props.macs">
                {{item.props.macs[0]}}
              </td>
              <td v-else>No mac found</td>
              <td >{{item.props.related_tap}}</td>
              <td>{{item.props.os_name}}</td>
              <td>{{item.props.os_version}}</td>
              <td >
                <v-container v-if="item.props.lastScan">
                  {{timeConverter(item.props.lastScan)}}
                </v-container>
                 <v-container v-else>
                  N/A
                </v-container>
              </td>

              <td>
                <v-tooltip open-delay=500 bottom>
                    <template v-slot:activator="{on, attrs}">
                        <v-btn @click="scanDevice(item)" color="grey lighten-3" v-bind="attrs" v-on="on" small class="mr-1" >
                          <v-icon

                          >
                            mdi-magnify-scan
                          </v-icon>
                        </v-btn>
                    </template>
                    <span>Start scan</span>
                </v-tooltip>
              </td>
            </tr>
          </template>
        </v-data-table>
  </div>
</template>

<script>

    import {execApiCmd} from "../../plugins/myutil"
    import {lstDevices} from '../../plugins/utilDbDevices'

    export default {
      name: 'nmapVue',
      data() {
        return {
          headers:[
            { text:'Ip address', sortable:false, value:'ip'},
            { text:'Mac adress', sortable:true, value:'props.os_name' },
            { text:'Related tap', sortable:true, value:'props.related_tap' },
            { text:'OS name', value:'props.os_name',sortable:true },
            { text:'OS version', value:'props.os_version',sortable:true },
            { text:'Last scan', value:'props.lastScan',sortable:true },
            { text:'Actions', sortable:true },

          ],
          list:[],
          ip:"",
          tab:null,
          taps:[],
          currentTap:"test"
        }
      },
      methods: {
        scanTap() {
          console.log(this.currentTap)
          execApiCmd('nmap', 'launchNmap',{'list':[this.currentTap]}, () => {
            lstDevices().then(
              (ans) => {
                this.list = ans.data
              }
            )
          })
        },
        scanDevice(item) {
          execApiCmd('nmap', 'scanDevice',item, x => {
            console.log("là")
            console.log(x)
            if(x == "Requête impossible, pas de tap trouvé")
              alert("Pas de tap trouvé pour "+item.ip+", scan impossible")
            lstDevices().then(
              (ans) => {
                this.list = ans.data
              }
            )
          })
        },
        timeConverter(UNIX_timestamp) {
              var a = new Date(UNIX_timestamp);
              var months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
              var year = a.getFullYear();
              var month = months[a.getMonth()];
              var date = a.getDate();
              var hour = a.getHours();
              var min = a.getMinutes();
              var sec = a.getSeconds();
              var time = date + ' ' + month + ' ' + year + ' ' + hour + ':' + min + ':' + sec;
              return time;
          }
      },
      mounted() {
        lstDevices().then(
          (ans) => {

            this.list = ans.data

          }
        )
        execApiCmd('taps', 'getTapConf',{}, x => {
          for(let item of x){
            this.taps.push(item.idname)
          }
        })

      }
    }

</script>

<style scoped >
.maxWidth{
  max-width: 250px;
}
</style>
