<script>
    /*eslint no-unused-vars: "off"*/
import { execApiCmd } from '../../plugins/myutil'
import { delDevice, addDevice, lstDevices, setDeviceProp, getDeviceProp } from '../../plugins/utilDbDevices'
import ipValidator from '../../plugins/ipValidator'

export default {
    name: "cpe.vue",
    data() {
        return {
            addDeviceDialog: {
                show: false,
                valid: true,
                rules: [
                    v => !!v || 'Required',
                    v => ipValidator(v) || 'Invalid IP'
                ],
                data: {
                    ip: '',
                    props: {
                        vul_level: 0,
                        type_icon: 'pc',
                    }
                }
            },
            expanded: [],
            menuNewDevice: {
                show: false,
                ipField: "",
                ipHint: "testhint",
                rules: [
                    value => !!value || 'Required.'
                ]
            },
            page: 0,
            filter: '',
            macEditStr: '',
            devices: [],
            vendors: [],
            products: [],
            versions: [],
            prefixes: [],
            search: "",
            number:{},
            loading:false,
            columns: [
                {text: 'Name', value: 'props.name'},
                {text: 'IP', value: 'ip'},
                {text: 'Software', value: null},
                {text: 'Tracked', value: 'os_cpe_tracked', filterable: true},
                {text: 'CPE Préfix', value: 'os_cpe_pref', filterable: true},
                {text: 'Vendor', value: 'os_cpe_vendor', filterable: true},
                {text: 'Product', value: 'os_cpe_product', filterable: true},
                {text: 'Version', value: 'os_cpe_version', filterable: true},
                {text: 'Vulnérability count', value: 'os_cve_count', filterable: true}
            ],
            columnsSoft:[
                {text: 'version', value: 'version', filterable: true},
                {text: 'CPE Préfix', value: 'cpe_pref', filterable: true},
                {text: 'Tracked', value: 'cpe_tracked', filterable: true},
                {text: 'Vendor', value: 'cpe_vendor', filterable: true},
                {text: 'Product', value: 'cpe_product', filterable: true},
                {text: 'Version', value: 'cpe_version', filterable: true},
                {text: 'Vulnérability count', value: 'cve_count', filterable: true}
            ],
        }
    },
    methods: {
        addDevice() {
            this.$nextTick(() => {
                this.$refs.addDeviceForm.validate()
                if(this.addDeviceDialog.valid) {
                    addDevice(this.addDeviceDialog.data.ip, this.addDeviceDialog.data).then(
                        ans => {
                            if(typeof ans.data.error == 'undefined') {
                                this.addDeviceDialog.show = false
                                var tempJson = ans.data
                                if(tempJson["props"]["os_cpe"] != null){
                                    tempJson.os_cpe_pref = tempJson["props"]["os_cpe"].split(":")[1]
                                    tempJson.os_cpe_vendor = tempJson["props"]["os_cpe"].split(":")[2]
                                    tempJson.os_cpe_product = tempJson["props"]["os_cpe"].split(":")[3]
                                    tempJson.os_cpe_version = tempJson["props"]["os_cpe"].split(":")[4]
                                }
                                let j;
                                let tempSoftwares= []
                                if(typeof tempJson.props.softwares != 'undefined') {
                                    for(j = 0 ; j < tempJson.props.softwares.length; j++){
                                        let tempSoft = JSON.parse(JSON.stringify(tempJson.props.softwares[j]))
                                        let tempCpe
                                        if(Array.isArray(tempSoft.cpe)){
                                            tempCpe = tempSoft.cpe[0]
                                        }
                                        else{
                                            tempCpe = tempSoft.cpe
                                        }
                                        if(tempCpe && tempCpe != null && tempCpe != "null"){
                                            let tempCpeSplit = tempCpe.split(":")
                                            tempSoft.cpe_pref = tempCpeSplit[1]
                                            tempSoft.cpe_vendor = tempCpeSplit[2]
                                            tempSoft.cpe_product = tempCpeSplit[3]
                                            tempSoft.cpe_version = tempCpeSplit[4]
                                        }
                                        tempSoftwares.push(tempSoft)

                                    }
                                    delete tempJson.props.softwares
                                }
                                tempJson.props.softwares = tempSoftwares
                                this.devices.push(tempJson)
                            }
                        }
                    )
                }
            })
        },
        expandAll() {
            console.log("All expanded.");
            this.$data.expanded = this.$data.devices;
        },
        getColor (cve_count) {
            console.log(cve_count)
            if (cve_count > 30) return 'red'
            else if (cve_count > 15) return 'orange'
            else return 'green'
        },
        getText (cve_count) {
            console.log("text : "+cve_count)
            if (cve_count == undefined) return 'N/A'
            else return cve_count

        },
        splitCpe(nb,test){
            console.log(test)
            return test.split(':')[nb];
        },
        sanitizedSoftware(soft) {
            let newSoft = Object.assign({}, soft.props)
            return newSoft
        },
        sanitizedItem(item) {
            let newItem = JSON.parse(JSON.stringify(item))
            if(typeof newItem.id != 'undefined')
                delete newItem.id
            if(typeof newItem.props.cpe != 'undefined')
                newItem.props.cpe = this.stringifyCpe(newItem.props.cpe)
            return newItem
        },
        stringifyCpe(cpe) {
            let s
            s = cpe[0]+':'+cpe[1]+':'+cpe[2]+':'+cpe[3]+':'+cpe[4]
            return s
        },
        loadDevices() {
            let THIS = this
            lstDevices().then(x => {
                x = x.data
                var i;
                var newresult = [];
                for(i = 0 ; i< x.length;i++){
                    var tempJson = x[i]
                    if(tempJson["props"]["os_cpe"] != null){
                        tempJson.os_cpe_pref = tempJson["props"]["os_cpe"].split(":")[1]
                        tempJson.os_cpe_vendor = tempJson["props"]["os_cpe"].split(":")[2]
                        tempJson.os_cpe_product = tempJson["props"]["os_cpe"].split(":")[3]
                        tempJson.os_cpe_version = tempJson["props"]["os_cpe"].split(":")[4]
                    }
                    let j;
                    let tempSoftwares= []
                    if(typeof tempJson.props.softwares != 'undefined') {
                        for(j = 0 ; j < tempJson.props.softwares.length; j++){
                            let tempSoft = JSON.parse(JSON.stringify(tempJson.props.softwares[j]))
                            let tempCpe
                            if(Array.isArray(tempSoft.cpe)){
                                tempCpe = tempSoft.cpe[0]
                            }
                            else{
                                tempCpe = tempSoft.cpe
                            }
                            if(tempCpe && tempCpe != null && tempCpe != "null"){
                                let tempCpeSplit = tempCpe.split(":")
                                tempSoft.cpe_pref = tempCpeSplit[1]
                                tempSoft.cpe_vendor = tempCpeSplit[2]
                                tempSoft.cpe_product = tempCpeSplit[3]
                                tempSoft.cpe_version = tempCpeSplit[4]
                            }
                            tempSoftwares.push(tempSoft)

                        }
                        delete tempJson.props.softwares
                    }
                    tempJson.props.softwares = tempSoftwares
                    newresult.push(tempJson)
                }
                console.log("modified devices")
                console.log(newresult)
                this.devices =  newresult
                this.expandAll()
            })
        },
        getCpePrefixes() {
            let THIS = this

            execApiCmd('cpe', "getPrefix",{},  (json) => {
                THIS.prefixes = json
            })
        },
        getCpeVendors(prefix) {
            let THIS = this
            execApiCmd('cpe', "getVendor",
                {prefix: prefix},
                (json) => {
                    json.push("*")
                    THIS.vendors = json
                })
        },
        getCpeProducts(prefix, vendor) {
            let THIS = this
            execApiCmd('cpe', "getProduct",
                {prefix: prefix, vendor: vendor},
                (json) => {
                    json.push("*")
                    THIS.products = json
                })
        },
        getCpeVersions(prefix, vendor, product) {
            let THIS = this
            execApiCmd('cpe', "getVersion",
                {prefix: prefix, vendor: vendor, product: product},
                (json) => {
                    json.push("*")
                    THIS.versions = json
                })
        },
        prefixeInput(item) {
            console.log("this is ")
            console.log(item)

            this.save(item, 'cpe', item.os_cpe_pref)
            this.getCpeVendors(item.os_cpe_pref)
            this.products = []
            this.versions = []
        },
        vendorInput(item) {
            this.save(item, 'cpe', item.os_cpe_vendor)
            this.getCpeProducts(item.os_cpe_pref, item.os_cpe_vendor)
            this.versions = []
        },
        productInput(item) {
            this.save(item, 'cpe', item.os_cpe_product)
            this.getCpeVersions(item.os_cpe_pref, item.os_cpe_vendor, item.os_cpe_product)
        },
        versionInput(item) {
            this.save(item, 'cpe', item.os_cpe_version)
        },
        /*eslint no-fallthrough: 0*/
        save (item, prop, value, isService) {
            let THIS = this
            let path, currentSoft, rebuiltCpe, ip

            switch(prop) {
                case 'tracked_software':
                    ip = item
                    path = 'props.softwares.'+value+'.cpe_tracked'
                    setDeviceProp(ip, path, isService).then(() => {
                        THIS.snackText = 'Data saved'
                    })
                    break;
                case 'tracked_os' :
                    ip = item
                    path = 'props.os_cpe_tracked'
                    setDeviceProp(ip, path, value).then(() => {
                        THIS.snackText = 'Data saved'
                    })
                    break;
                case 'os_name':
                    ip = item.ip
                    path = 'props.os'
                    console.log("changing "+ip+"'s path "+path+" to "+item.props.os)
                    setDeviceProp(ip, path, item.props.os).then(() => {
                        THIS.snackText = 'Data saved'
                    })
                    break;
                case 'software_name':
                    ip = this.findParent(value).ip
                    path = 'props.softwares.'+value+'.name'
                    currentSoft = item.props.softwares[value];
                    rebuiltCpe = currentSoft.name
                    console.log("changing "+ip+"'s path "+path+" to "+rebuiltCpe)
                    setDeviceProp(ip, path, rebuiltCpe).then(() => {
                        THIS.snackText = 'Data saved'
                    })
                    break;
                case  'software_cpe':
                    ip = this.findParent(value).ip
                    currentSoft = item.props.softwares[value];
                    rebuiltCpe = "cpe"+':'+currentSoft.cpe_pref+':'+currentSoft.cpe_vendor+':'+currentSoft.cpe_product+':'+currentSoft.cpe_version;
                    currentSoft.cpe = rebuiltCpe
                    setDeviceProp(ip, path, rebuiltCpe).then(() => {
                        THIS.snackText = 'Data saved'
                    })
                    break;
                case 'os_cpe':
                    ip = item.ip
                    path = 'props.'+prop
                    value = "cpe"+':'+value.os_cpe_pref+':'+value.os_cpe_vendor+':'+value.os_cpe_product+':'+value.os_cpe_version
                    setDeviceProp(ip, path, value).then(() => {
                        THIS.snackText = 'Data saved'
                    })
                    break;

                default:
                    break;
            }


        },
        cancel () {
            this.snack = true
            this.snackColor = 'error'
            this.snackText = 'Canceled'
        },
        pathOf(item) {
            let i, j
            for(i = 0; i < this.devices.length; ++i) {
                if(this.devices[i].id == item.id) {
                    return [this.devices[i].ip]
                } else {
                    for(j = 0; j < this.devices[i]._children.length; ++j) {
                        if(this.devices[i]._children[j] == item.id) {
                            return [this.devices[i].ip, j]
                        }
                    }
                }
            }
        },
        newMac(item, mac) {
            let THIS = this
            let parent = this.findParent(item)
            let ip = parent.ip
            let path = 'macs'
            setDeviceProp(ip, path, mac).then((ans) => {
                item.macs.push(mac)
                THIS.snack = true
                THIS.snackColor = 'success'
                THIS.snackText = 'Data saved'
            })
        },
        fromServerJSONtoWorkingJSON(devices) {
            return devices
        },
        findParent(item) {
            console.log(item)
            let i, j
            for(i = 0; i < this.devices.length; ++i) {
                if(this.devices[i].id == item.id) {
                    return this.devices[i]
                } else {
                    if(typeof this.devices[i]._children != 'undefined') {
                        for(j = 0; j < this.devices[i]._children.length; ++j) {
                            if(this.devices[i]._children[j].id == item.id) {
                                return this.devices[i]
                            }
                        }
                    }
                }
            }
        },
        open () {
            this.snack = true
            this.snackColor = 'info'
            this.snackText = 'Dialog opened'
        },
        close () {
            console.log('Dialog closed')
        },
        filterChanged (filter) {
            this.filter = filter;
        },
        pageChanged (page) {
            this.page = page;
        },
    },
    mounted() {
        this.loadDevices()
        this.getCpePrefixes()
        this.addDeviceDialog.rules.push(
            v => this.devices.find(x => x.ip == v) == undefined || 'Machine with this IP already exists'
        )
    }
}
</script>

