<template>
  <v-main id="inspire">
      <v-card-title v-if="isLarge">
        <v-row class ="mt-n7">
          <v-col
            cols="auto"

          >
            <v-text-field
              v-model="search"
              append-icon="mdi-magnify"
              label="Search"
              single-line
              hide-details
            ></v-text-field>
          </v-col>
          <v-col

          >
            <v-btn
              @click="reloadCve()"
              :loading="loading"
              depressed
              elevation="2"
              large
              color="light-grey"

            >
              <v-icon class="mr-3">
                mdi-reload
              </v-icon>
              Refresh vulnerabilities</v-btn>
          </v-col>
        </v-row>
      </v-card-title>

      <v-data-table
        :loading=[true]
        loading-text="Loading... Please wait"
        :headers="headers"
        :items="list"
        :search="search"
        :items-per-page="15"
        :sort-by="['cvss']"
        :sort-desc="[true]"
        dense
        item-key="summary"
        :single-expand="true"
      >
      <template v-if="!this.isLarge" v-slot:item="{ item, expand, isExpanded }" >
        <tr @click="expand(!isExpanded)">
          <td :class = '[{"truncate": !isLarge}]'>
            {{ item.summary }}
          </td>
          <td>
            <v-chip
            :color="getColor(item.cvss)"
            dark
            small
            >
              {{ item.cvss }}
            </v-chip>
          </td>
        </tr>
      </template>

      <template v-else v-slot:item="{ item }" >
        <tr cellspacing="0" cellpadding="0">
          <td >
            {{ item.id }}
          </td>
          <td >
            {{ item.ip }}
          </td>
          <td>
            <v-chip
            :color="getColor(item.cvss)"
            dark
            small
            >
              {{ item.cvss }}
            </v-chip>
          </td>
           <td >
            {{ item.cwe }}
          </td>
           <td >
            {{ item.summary }}
          </td>
            <td >
              <v-container class="ml-n4">
                <div v-if="item.impact.integrity">
                  Integrity : {{ item.impact.integrity }}<br/>
                </div>
                <div v-if="item.impact.confidentiality">
                  Confidentiality : {{ item.impact.confidentiality }}<br/>
                </div>
                <div v-if="item.impact.availability">
                  Availability : {{ item.impact.availability }}
                </div>
              </v-container>

          </td>
            <td >
            <v-container class="ml-n4">
              <div v-if="item.access.accessVector">
                Vector : {{ item.access.accessVector }}<br/>
              </div>
              <div v-if="item.access.accessComplexity">
                Complexity : {{ item.access.accessComplexity }}<br/>
              </div>
              <div v-if="item.access.authentification">
                Authentification : {{ item.access.authentification }}
              </div>
            </v-container>
          </td>
        </tr>
      </template>

      <template v-if="!this.isLarge" v-slot:expanded-item="{ item }" >
          <td :colspan="headers.length*2">
            <v-card-text >
              <h5>Description :</h5>
              {{item.summary}}
              <br/><br/>
              <h5>Impact :</h5>
              Integrity : {{ item.impact.integrity }}<br/>
              Confidentiality : {{ item.impact.confidentiality }}<br/>
              Availability : {{ item.impact.availability }}
              <br/><br/>
              <h5>Access Vector :</h5>
              Vector : {{ item.access.accessVector }}<br/>
              Complexity : {{ item.access.accessComplexity }}<br/>
              Authentification : {{ item.access.authentification }}
              <br/>
              <br/>
              <h5>Associated weakness :</h5> {{ item.cwe }}
              <br/>
              <br/>
              <h5>Vulnerability reference :</h5> {{ item.id }}
            </v-card-text>
          </td>
      </template>


      </v-data-table>
  </v-main>
</template>

<script>
    import {execApiCmd} from "../../plugins/myutil";

    export default {
        name: 'cslVulns',
        data() {
          return {
            loading : false,
            expanded: [],
            search: '',
            list: []
          }

        },
        methods: {
          reloadCve(){
              this.loading = true;
              execApiCmd('cve', "updateCve",this.toFetch,() => {
                execApiCmd('cve', "getCve",this.toFetch,this.setJson)
              })

          },
          setJson(result){
            this.list = result;
            this.loading = false;
          },
          getColor (cvss) {
            if(cvss < 3){
                return "#88ccff"
              }
              else if(cvss < 5){
                return "#f8e847"
              }
              else if(cvss < 8){
                return "#fa8b30"
              }
              else if(cvss < 11){
                return "#fb1826"
              }
              else return "#bfbfbf"
          }
        },
        mounted() {
          execApiCmd('cve', "getCve",this.toFetch,this.setJson);
        },
        props:{
            machine:{
              type:Object
            },
            isLarge:{
              type:Boolean ,
              default:true
            },
            allMachines:{
              type:Boolean ,
              default:true
            }
        },
        watch:{
          machine: function(){
            this.list = [];
            execApiCmd('cve', "getCve",this.toFetch,this.setJson);
          }
        },
        computed: {
          toFetch (){
            if(this.allMachines){
              return {"mode":"any"};
              }
              else{
                return {"mode":this.machine.id};
              }
          },
          headers() {
            console.log(this.isLarge)
            if(this.isLarge)
              return [
                { text:'CVE ID', value:'id' },
                { text:'Node IP', value:'ip' },
                { text:'CVSS score', value:'cvss'},
                { text:'CWE', value:'cwe'},
                { text:'Summary', value:'summary' },
                { text:'Impact', value:'impact.integrity' , width: "250px"},
                { text:'Vector', value:'access.accessVector' , width: "235px"},
                ];
            else{
              return [
                { text:'Summary', value:'summary' },
                { text:'CVSS score', value:'cvss' },
                ];
            }
          }
        }

    }

</script>

<style lang="css" >
    .truncate {
      max-width: 270px;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }

</style>
