<template>
    <div>
        <!--
        <div>
            <v-btn @click="refreshParams">Refresh Params</v-btn>
            <v-btn @click="clearConsole">Clear console</v-btn>

        </div>
--><v-col class="text-left">

        <b>
            IDS MODE : {{this.global.ids_mode}}</b>
        <br>

    </v-col>
        <div>
            <v-btn @click="startLearning">Start Learning</v-btn>
            <v-btn @click="cancelLearning">Cancel and restore previous model</v-btn>



        </div>
        <v-expansion-panels>
            <v-expansion-panel @click="onExpansionPanelClick1">
                <v-expansion-panel-header>Learning params   </v-expansion-panel-header>
                <v-expansion-panel-content>


                    <v-simple-table>

                        <tbody>
                        <tr v-for="item in learning_params" :key="item.name">
                            <td>{{ item.name }}</td>
                            <td> {{ item.value }}</td>
                        </tr>
                        </tbody>

                    </v-simple-table>

                </v-expansion-panel-content>
            </v-expansion-panel>
        </v-expansion-panels>



        <DataSetList type="2" @refresh="refreshParams" ></DataSetList>
        <h3>&nbsp;</h3>


        <v-col class="text-right">

            <v-btn x-small @click="clearConsole">Clear Console</v-btn>
        </v-col>
        <div class="t0"  ref="container">
            <p class="t1" v-html="logs"></p>
        </div>

        <div>  <br><br><v-btn @click="resetLearnedModel">Reset learned model</v-btn>
            <v-btn @click="addToDbDevices">Add to Model</v-btn>
            <v-btn @click="refreshLearnedModelTable">Refresh Model Table</v-btn>
            <v-btn @click="refreshDevicesTable">Refresh Devices Table</v-btn>
        <v-btn @click="refreshLearnedModelDpiTable">Refresh Modbus Table</v-btn></div>
        <ModelTable :rows="model_rows" :title="title_model"></ModelTable>
        <ModelTable :rows="devices_rows" :title="title_devices"></ModelTable>

    <ModelTableDpi :rows="model_dpi_rows" :title="title_model_dpi"></ModelTableDpi>

    </div>
</template>

<script>
    import axios from "axios";
    import {execCmd, generateUUID,asyncExecApiCmd, execApiCmd} from "../../plugins/myutil";
    import DataSetList from "./DataSetList";
    import ModelTable from "@/components/ids/ModelTable";
    import ModelTableDpi from "@/components/ids/ModelTableDpi";
    import {config} from "@/plugins/config";
    const MAXLINES=25;


    const SHOW_LEARNED_MODEL_TABLE="show_learned_model_table";
    const SHOW_DEVICES_MODEL_TABLE="show_devices_model_table";
    const SHOW_CONSOLE_ON_HMI_LEARNING_PAGE="show_console_on_hmi_learning_page";


    let my_uuid = generateUUID();
   // let s_url = "ws://" + "127.0.0.1" + ":" + "8000" + "/console";
    let s_url =
        config.websocketUrl() +"/console";

    export default {
        name: "TabLearning",
        components: {DataSetList,ModelTable,ModelTableDpi},
        props:['global'],
        data: function () {
            return {
                dataset:"",
                ids_mode:"",
                model_rows:[],
                model_dpi_rows:[],

                devices_rows:[],
                title_model:"Learned Model",
                title_devices:"Devices Model",
                title_model_dpi:"Modbus Model",

                learning_params:[
                {
                    name: 'Start Taps',

                    value:'click',

                },
                {
                    name: 'Stop Taps',

                    value:''

                }


                ],
                logs:"",
                xlogs: []
            }
        },

        methods : {

            startLearning() {
                execApiCmd("ids", "start_learning")
                this.refreshParams();
            },
            cancelLearning() {
                execApiCmd("ids", "cancel_learning")
                this.refreshParams();
            },
            resetLearnedModel() {
                execApiCmd("ids", "reset_learned_model")
            },

            addToDbDevices() {
                execApiCmd("ids", "add_to_dbdevices")


            },

            refreshLearnedModelTable() {
                let _this=this;
                execApiCmd("ids","get_learned_model_table",{},
                    function (value) {
                        _this.model_rows=value;


                    } );
            },

            refreshLearnedModelDpiTable() {
                let _this=this;
                execApiCmd("ids","get_learned_model_dpi_table",{},
                    function (value) {
                        _this.model_dpi_rows=value;


                    } );
            },

            refreshDevicesTable() {
                let _this=this;
                execApiCmd("ids","get_devices_table",{},
                    function (value) {
                        _this.devices_rows=value;


                    } );
            },  
            onExpansionPanelClick1(event) {
               // alert('test');
                if(event.currentTarget.classList.contains('v-expansion-panel-header--active')) {
                    console.log("Panel is closing/now closed.")
                } else {
                    console.log("Panel is opening/now open.")
                }
            },
            refreshParams () {
                let _this=this;
                execApiCmd("ids","get_CSL_learning_args",{},
                    function (value) {
                        _this.learning_params=value;
                        for (let keyvalue of _this.learning_params) {
                            console.log(keyvalue)
                            console.log("key="+keyvalue.name.toLowerCase())
                            if (keyvalue.name.toLowerCase()==="dataset") _this.dataset=keyvalue.value;
                            if (keyvalue.name.toLowerCase() === "ids_mode") {
                                keyvalue.show_always=true;
                                _this.ids_mode=keyvalue.value;
                               // _this.global.ids_mode=keyvalue.value+ "";
                            }
                        }

                } );


            },



            scrollToEnd () {
                var content = this.$refs.container;
                content.scrollTop = content.scrollHeight;
            },

            addLine(line) {
                this.xlogs.push(line);
                if (this.xlogs.length>MAXLINES) this.xlogs.shift();

                let s = "";
                //let xlogs = ["line 1", "line 2", "line 3", "line 4"];
                for (let z of this.xlogs) {
                    s = s + z + '<br>'
                }
                this.logs= '<pre>' + s + '</pre>';
            },


            clearConsole() {
                this.xlogs=[];

            },
        },

        computed: {



        },


        activated: function() {
          alert('ok');
        },
        mounted: function () {
            axios.defaults.headers.common['Access-Control-Allow-Origin'] = '*';
            console.log("Mounting")


            this.refreshParams();

            let webSocket = new WebSocket(s_url);
            webSocket.onerror = function (error) {
                console.log("WEBSOCKET ERROR")
                console.log(error);
            };
            let THIS = this;

            console.log(webSocket);
            webSocket.onmessage = function (msg) {
               // console.log("WEBSOCKET");
               // console.log(msg.data);
                let data = JSON.parse(msg.data);
                //console.log(data);

                if (data.loginfo) {

                    if (data.loginfo.console_id==="learn")
                                THIS.addLine(data.loginfo.line);
                }


                if (data.loginfo.refresh_hmi) {
                    THIS.addLine('>');
                    THIS.refreshParams()
                }
                // this.xlogs.push(data.loginfo.line)
                /*if ('database' in data) {
                    let name=data.database.name;
                    let uuid=data.database.uuid;
                    console.log("modified json file :"+name+"   uuid="+uuid+"  myuuid="+my_uuid);

                }*/

                THIS.scrollToEnd();

                //updateChat(msg);
            };
            webSocket.onclose = function () {
              //  alert("WebSocket connection closed LearningTab")
            };


        }
    }
</script>

