import Vue from 'vue'
import App from './App.vue'
import router from './router'
import vuetify from './plugins/vuetify';
//import BootstrapVue from 'bootstrap-vue'
import {store} from './store/store'
import * as tags_actions from "./store/tags-actions";

Vue.config.productionTip = false

Vue.mixin({
  data: function() {
    return {
      myGlobalVar:'this is my ItSolutionStuff.com',
      xGlobal : {'version':0.01}
    }
  }
})

Vue.prototype.$xGlobal= {'version':0.01}

new Vue({
  router,
  vuetify,
  render: h => h(App),
  store: store,
  created: function () {
    // `this` points to the vm instance
    console.log('a is: ' + this.store)
    this.$store.dispatch(tags_actions.INIT_STORE)

  }
}).$mount('#app')