    mounted() {
        execApiCmd('nmap', 'getLinksNumber',{}, x => {
          this.linksNumber = x.number;
        })
        execApiCmd('taps', 'tapNumber',{}, x => {
          this.tapsNumber = x.number;
        })
        lstDevices().then((x) => {
          this.deviceNumber = Array.from(x.data).length;
        });
        execApiCmd("ids","op_alert",{'op':'get_list_all'}, x => {
            let donnees = {};
            donnees.unknown = 0
            donnees.debug = 0
            donnees.critical = 0
            donnees.warning = 0
            donnees.info = 0
            this.alertNumber = x.length
            if(this.alertNumber == 0){
              this.dataAlerts = [
                { value: 0, name: "Critical", itemStyle:{ color:"#fb1826"} },
                { value: 0, name: "Moderate", itemStyle:{ color:"#fa8b30"} },
                { value: 0, name: "Info", itemStyle:{ color:"#f8e847"} },
                { value: 0, name: "Debug", itemStyle:{ color:"#88ccff"} },
                { value: 0, name: "Unknown", itemStyle:{ color:"#bfbfbf"} }
              ]
              this.majGraphAlerts();
              return;
            }
            for(let i of x){
              switch(i.level){
                case 'DEBUG':
                  donnees.debug = donnees.debug+1
                  break;
                case 'INFO':
                  donnees.info = donnees.info+1
                  break;
                case 'MODERATE':
                  donnees.warning = donnees.warning+1
                  break;
                case 'CRITICAL':
                  donnees.critical = donnees.critical+1
                  break;
                default:
                  donnees.unknown = donnees.unknown+1
                  break;
              }
            }
            let finalRes = []
            if(donnees.critical > 0)
              finalRes.push({ value: donnees.critical, name: "Critical", itemStyle:{ color:"#fb1826"} })
            if(donnees.warning > 0)
              finalRes.push({ value: donnees.warning, name: "Moderate", itemStyle:{ color:"#fa8b30"} })
            if(donnees.info > 0)
              finalRes.push({ value: donnees.info, name: "Info", itemStyle:{ color:"#f8e847"} })
            if(donnees.debug > 0)
              finalRes.push({ value: donnees.debug, name: "Debug", itemStyle:{ color:"#88ccff"} })
            if(donnees.unknown > 0)
              finalRes.push({ value: donnees.unknown, name: "Unknown", itemStyle:{ color:"#bfbfbf"} })

            this.dataAlerts = finalRes;
            this.majGraphAlerts();
          }
        );
        execApiCmd("cve","getCve","any", x => {
            console.log("c'est là")
            console.log(x)
            let donnees = {};
            donnees.unknown = 0
            donnees.low = 0
            donnees.medium = 0
            donnees.high = 0
            donnees.max = 0
            this.VulnNumber = x.length
            if(this.VulnNumber == 0){
              this.dataVuln = [
                { value: 0, name: "Very high", itemStyle:{ color:"#fb1826"} },
                { value: 0, name: "High", itemStyle:{ color:"#fa8b30"} },
                { value: 0, name: "Medium", itemStyle:{ color:"#f8e847"} },
                { value: 0, name: "Low", itemStyle:{ color:"#88ccff"} }
              ]
              this.majGraphVuln();
              return;
            }
            for(let i of x){
              console.log(i.cvss)
              if(i.cvss < 3){
                donnees.low = donnees.low+1
              }
              else if(i.cvss < 5){
                donnees.medium = donnees.medium+1
              }
              else if(i.cvss < 8){
                donnees.high = donnees.high+1
              }
              else if(i.cvss < 11){
                donnees.max = donnees.max+1
              }
              else{
                donnees.unknown = donnees.unknown+1
              }
            }
            let finalRes = []
            if(donnees.max > 0)
              finalRes.push({ value: donnees.max, name: "Very high", itemStyle:{ color:"#fb1826"} })
            if(donnees.high > 0)
              finalRes.push({ value: donnees.high, name: "High", itemStyle:{ color:"#fa8b30"} })
            if(donnees.medium > 0)
              finalRes.push({ value: donnees.medium, name: "Medium", itemStyle:{ color:"#f8e847"} })
            if(donnees.low > 0)
              finalRes.push({ value: donnees.low, name: "Low", itemStyle:{ color:"#88ccff"} })
            if(donnees.unknown > 0)
              finalRes.push({ value: donnees.unknown, name: "Unknown", itemStyle:{ color:"#bfbfbf"} })

            this.dataVuln = finalRes;
            console.log(this.dataVuln)
            this.majGraphVuln();
          }
        );
        },
