import {asyncExecApiCmd} from "@/plugins/myutil";



export async function opDbDevices(user,operation,id="",id2="", path="",value={},mode_ip=true) {
    try {
        let x = await asyncExecApiCmd("devdb","op",
            {op:operation,user:user, id:id,id2:id2,path:path,value:value,mode_ip:mode_ip})
        console.log('devicesDBOperation:'+operation+ ' , result=')
        console.log(x)


        return x;
    } catch (error) {
        throw  new Error('Error in opDataSet ' + error)
    }

}

