<script>
    /*eslint no-unused-vars: "off"*/
//import '../../../node_modules/vue-ads-table-tree/dist/vue-ads-table-tree.css'
import VueAdsTableTree from 'vue-ads-table-tree'
import {setDeviceProp, clear, getLinksFrom, delLinkProps, delLink, addLink, addDevice, addLinkProps, lstDevices, getLink, setLinkProps} from '../../plugins/utilDbDevices'
import ipValidator from '../../plugins/ipValidator'

export default {
    name: 'flowsTab',
    components: {
        VueAdsTableTree
    },
    data() {
        return {
            addDeviceDialog: {
                show: false,
                valid: true,
                rules: [
                    v => !!v || 'Required',
                    v => ipValidator(v) || 'Invalid IP'
                ],
                data: {
                    ip: '',
                    props: {
                        vul_level: 0,
                        type_icon: 'pc',
                    }
                }
            },
            menuNewFlow: {
                rules: [
                    v => !!v || 'Required',
                    v => ipValidator(v) || 'Invalid IP'
                ],
                show: false,
            },
            formValid: '',
            newItem: {
                protocol: '',
                app_protocol: '',
                port_src: '',
                port_dst: '',
                ip: '',
                ip_dst: '',
                direction: 1,
                flow: {
                    severity: '',
                    likelyhood: '',
                    maxKBpersec: '',
                    maxpktpersec: '',
                    first_time: '',
                    last_time: '',
                }
            },
            directionIcons: [ 'mdi-arrow-left', 'mdi-arrow-right', 'mdi-arrow-left-right' ],
            page: 0,
            filter: '',
            flows: [],
            devices: [],
            knownDevices: [],
            columns: [
                {title: 'Edit', property: 'edit'},
                {title: 'IP src', property: 'ip', filterable: true, direction: null, collapseIcon: true},
                {title: 'IP dst', property: 'ip_dst', filterable: true},
                {title: 'Port src', property: 'port_src', filterable: true},
                {title: 'Port dst', property: 'port_dst', filterable: true},
                {title: 'Protocol', property: 'protocol', filterable: true},
                {title: 'App Protocol', property: 'app_protocol', filterable: true},
                {title: 'Max Flowrate', property: 'maxKBpersec', filterable: true},
                {title: 'Last time', property: 'last_time', filterable: true},
                {title: 'Likelyhood', property: 'likelyhood', filterable: true},
            ],
            search: '',
            editDialogOldValue: '',
            snack: false,
            snackColor: '',
            snackText: '',
            max25chars: v => v.length <= 25 || 'Input too long!',
        }
    },
    methods: {
        addDevice() {
            this.$nextTick(() => {
                this.$refs.addDeviceForm.validate()
                if(this.addDeviceDialog.valid) {
                    addDevice(this.addDeviceDialog.data.ip, this.addDeviceDialog.data).then(
                        ans => {
                            if(typeof ans.error == 'undefined') {
                                let dev = ans.data
                                this.addDeviceDialog.show = false
                                this.devices.push({
                                    ip: dev.ip,
                                    id: dev.uuid
                                })
                                this.snack = true
                                this.snackColor = 'success'
                                this.snackText = 'Data saved'
                            } else {
                                this.snack = true
                                this.snackColor = 'error'
                                this.snackText = 'Error'
                            }
                        }
                    )
                }
            })
        },
        open(old) {
            this.editDialogOldValue = old
            console.log(old)
            this.snack = true
            this.snackColor = 'info'
            this.snackText = 'Dialog opened'
        },
        async addLink() {
            let ipSrc, ipDst, promise
            this.$refs.form.validate()
            let valueOf = function(x) {
                if(typeof x != 'undefined') {
                    return x
                } else {
                    return 'undef.'
                }
            }
            if(this.formValid) {
                switch(this.newItem.direction) {
                case 0:
                    ipDst = this.newItem.ip
                    ipSrc = this.newItem.ip_dst
                    break
                case 1:
                    ipSrc = this.newItem.ip
                    ipDst = this.newItem.ip_dst
                    break
                case 2: {
                        ipSrc = this.newItem.ip
                        ipDst = this.newItem.ip_dst
                        let linkToAdd = JSON.parse(JSON.stringify(this.newItem))
                        delete linkToAdd.ip
                        delete linkToAdd.ip_dst
                        delete linkToAdd.direction
                        let ans = await getLink(ipDst, ipSrc)
                        let newArc =typeof ans.data.result != 'undefined' && ans.data.result == 'NO_LINK'
                        if(newArc) {
                            promise = addLink
                        } else {
                            promise = addLinkProps
                        }
                        promise(ipDst, ipSrc, linkToAdd).then(
                            ans => {
                                if(typeof ans.data.error == 'undefined') {
                                    let parent
                                    if(newArc) {
                                        console.log('back link '+ipDst+' a '+ipSrc+ ' cree')
                                        parent = {
                                            ip: ipDst,
                                            name: "",
                                        }
                                        this.flows.push(parent)
                                    } else {
                                        parent = this.flows.find(o => o.ip == ipDst)
                                    }
                                    this.addSubLink(parent, {
                                        likelyhood: valueOf(linkToAdd.flow.likelyhood),
                                        severity: valueOf(linkToAdd.flow.severity),
                                        protocol: valueOf(linkToAdd.protocol),
                                        app_protocol: valueOf(linkToAdd.app_protocol),
                                        port_src: valueOf(linkToAdd.port_src),
                                        ip_dst: valueOf(ipSrc),
                                        port_dst: valueOf(linkToAdd.port_dst),
                                        maxKBpersec: valueOf(linkToAdd.flow.maxKBpersec),
                                        maxpktpersec: valueOf(linkToAdd.flow.maxpktpersec),
                                        first_time: valueOf(linkToAdd.flow.first_time),
                                        last_time: valueOf(linkToAdd.flow.last_time)
                                    })
                                } else {
                                    console.log(ans.data.error)
                                }
                            }
                        )
                    }
                    break
                }
                let linkToAdd = JSON.parse(JSON.stringify(this.newItem))
                delete linkToAdd.ip
                delete linkToAdd.ip_dst
                delete linkToAdd.direction
                let ans = await getLink(ipSrc, ipDst)
                let newArc = typeof ans.data.result != 'undefined' && ans.data.result == 'NO_LINK'
                if(newArc) {
                    promise = addLink
                } else {
                    promise = addLinkProps
                }
                promise(ipSrc, ipDst, linkToAdd).then(
                    ans => {
                        if(typeof ans.data.error == 'undefined') {
                            let parent
                            if(newArc) {
                                parent = {
                                    ip: ipSrc,
                                    name: "",
                                }
                                this.flows.push(parent)
                            } else {
                                parent = this.flows.find(o => o.ip == ipSrc)
                            }
                            this.addSubLink(parent, {
                                likelyhood: valueOf(linkToAdd.flow.likelyhood),
                                severity: valueOf(linkToAdd.flow.severity),
                                protocol: valueOf(linkToAdd.protocol),
                                app_protocol: valueOf(linkToAdd.app_protocol),
                                port_src: valueOf(linkToAdd.port_src),
                                ip_dst: valueOf(ipDst),
                                port_dst: valueOf(linkToAdd.port_dst),
                                maxKBpersec: valueOf(linkToAdd.flow.maxKBpersec),
                                maxpktpersec: valueOf(linkToAdd.flow.maxpktpersec),
                                first_time: valueOf(linkToAdd.flow.first_time),
                                last_time: valueOf(linkToAdd.flow.last_time)
                            })
                        } else {
                            console.log(ans.data.error)
                        }
                    }
                )
            }
            this.menuNewFlow.show = false
        },
        async loadLinks() {
            let devices = []
            let flows = []
            let ans = await lstDevices()
            if(typeof ans.data.error == 'undefined') {
                for(let dev of ans.data) {
                    devices.push({
                        ip: dev.ip,
                        id: dev.uuid
                    })
                }
            }
            let valueOf = function(x) {
                if(typeof x != 'undefined') {
                    return x
                } else {
                    return 'undef.'
                }
            }

            this.devices = devices



            let i = 0, j = 0
            for(i = 0; i < devices.length; ++i) {
                let newLink = {
                    ip: devices[i].ip,
                    name: "",
                    links: [],
                }
                ans = await getLinksFrom(devices[i].ip)
                console.log('links ')
                console.log(ans.data)

                if(typeof ans.data.error == 'undefined') {
                    for(let arc of ans.data) {
                        console.log('arc ')
                        console.log(arc)

                        let ip_dst = devices.find(x => x.id == arc.dst_uuid).ip
                        for(let link of arc.sublinks) {
                            console.log('lien')
                            if(typeof link.flow == 'undefined')
                                link.flow = {}
                            newLink.links.push({
                                likelyhood: valueOf(link.flow.likelyhood),
                                severity: valueOf(link.flow.severity),
                                protocol: valueOf(link.protocol),
                                app_protocol: valueOf(link.app_protocol),
                                port_src: valueOf(link.port_src),
                                ip_dst: valueOf(ip_dst),
                                port_dst: valueOf(link.port_dst),
                                maxKBpersec: valueOf(link.flow.maxKBpersec),
                                maxpktpersec: valueOf(link.flow.maxpktpersec),
                                first_time: valueOf(link.flow.first_time),
                                last_time: valueOf(link.flow.last_time)
                            })
                        }
                        console.log("link added:")
                        console.log(newLink)
                    }
                } else {
                    console.log(ans.data.error)
                }
                //if(newLink.links.length)
                {
                    flows.push(newLink)
                    delete newLink.show
                }
            }
            console.log('fin')
            console.log(flows)
            this.devices = devices
            console.log("DEVICES")
            console.log(devices)

            this.flows = this.toTreeFormat({flows: flows})
            console.log(this.flows)
        },
        port(port) {
            let intVal = Number.parseInt(port)
            if(!Number.isNaN(intVal) && parseInt(port) <= 0) {
                return 'any'
            } else {
                return port
            }
        },
        toTreeFormat(json) {
            let obj
            let date = new Date()
            let time = date.getTime()
            obj = JSON.parse(JSON.stringify(json.flows))
            obj = obj.map((obj) => {
                obj.id = date++
                obj._children = obj.links.map((o) => {
                    o.id = date++
                    return o
                })
                delete obj.links
                return obj
            })
            return obj
        },
        cancelAdd() {
            this.$refs.form.reset()
            this.menuNewFlow.ipField = ""
            this.menuNewFlow.ipHint = ""
            this.menuNewFlow.show = false
        },
        addSubLink(parent, item) {
            console.log(parent)
            let replacement_item = JSON.parse(JSON.stringify(parent))
            if(typeof replacement_item._children == 'undefined') {
                replacement_item._children = []
            }
            replacement_item._children.push(item)
            this.flows.splice(this.flows.indexOf(parent), 1)
            this.flows.push(replacement_item)
        },
        addFlow() {
            this.menuNewFlow.ipHint = ""
            this.flows.push({
                id: new Date().getTime(),
                ip: this.menuNewFlow.ipField,
            })
        },
        close () {
            console.log('Dialog closed')
        },
        save(item, prop, value) {
            let THIS = this
            let parent = this.flows.find(x => typeof x._children.find(y => y.id == item.id) != 'undefined')
            let ip1 = parent.ip
            let ip2 = item.ip_dst
            if(prop == 'ip_dst') {
                getLink(ip1, ip2).then(
                    ans => {
                        console.log(ans)
                        if(typeof ans.data.result != 'undefined') {
                            if(ans.data.result == 'NO_LINK') {
                                addLink(ip1, ip2, {})
                            } else if(typeof ans.data.error != 'undefined') {
                                console.log(ans.data.error)
                            }
                        } else if(typeof ans.data.error != 'undefined') {
                            console.log(ans.data.error)
                        } else {
                            addLinkProps(ip1, ip2, {})
                        }
                    })
            } else {
                let id = parent._children.filter(x => x.ip_dst == ip2).indexOf(item)
                let path = id+'.'+prop
                setLinkProps(ip1, ip2, path, value).then(
                    ans => {
                        if(typeof ans.data.error != 'undefined') {
                            console.log(ans.data.error)
                        } else {
                            console.log(ans)
                            this.snack = true
                            this.snackColor = 'success'
                            this.snackText = 'Data saved'
                        }
                    })
            }
        },
        async removeSource(item) {
            for(let flow of item._children) {
                await delLink(item.ip, flow.ip_dst).then(
                    ans => {
                        if(typeof ans.data.error != 'undefined') {
                            console.log(ans.data.error)
                        }
                    }
                )
            }
            this.flows.splice(this.flows.indexOf(item), 1)
        },
        removeLink(item) {
            let THIS = this
            let link_id
            let child_id
            let flow = this.flows.find(o => {
                child_id = o._children.indexOf(item)
                if(child_id != -1) {
                    link_id = o._children.filter(x => x.ip_dst == item.ip_dst).indexOf(item)
                    return o
                }
            })
            delLinkProps(flow.ip, item.ip_dst, link_id).then(
                ans => {
                    if(typeof ans.data.error == 'undefined') {
                        flow._children.splice(child_id, 1)
                        THIS.removeEmpty()
                    } else {
                        console.log(ans.data.error)
                    }
                })
        },
        removeEmpty() {
            for(let flow of this.flows) {
                console.log('flow')
                console.log(flow)
                if(flow._children.length == 0) {
                    this.flows.splice(this.flows.indexOf(flow), 1)
                }
            }
        },
        cancel () {
            this.snack = true
            this.snackColor = 'error'
            this.snackText = 'Canceled'
        },
        filterChanged (filter) {
            this.filter = filter;
        },
        duplicate(item) {
            let d = new Date()
            let last_time = d.getTime()
            let changeID = function(o) {
                if(o != null) {
                    o.id = ++last_time
                    for(let child of o._children) {
                        changeID(child)
                    }
                }
            }
            let new_node = JSON.parse(JSON.stringify(item))
            changeID(new_node)
            this.flows.push(new_node)
        },
        pageChanged (page) {
            this.page = page;
        },
    },
    mounted() {
        this.loadLinks()
        lstDevices().then(
            ans => {
                this.knownDevices = ans.data
            }
        )
        this.addDeviceDialog.rules.push(
            v => this.knownDevices.find(x => x.ip == v) == undefined || 'Machine with this IP already exists'
        )
    }

}
</script>

