<template>
    <div>
        <!--
        <div>
            <v-btn @click="refreshParams">Refresh Params</v-btn>
            <v-btn @click="clearConsole">Clear console</v-btn>

        </div>
-->
        <v-col class="text-left">

            <b>
                IDS MODE : {{this.global.ids_mode}}</b>
            <br>

        </v-col>
        <div>
            <v-btn @click="startDetection">Start Detection Off line</v-btn>


        </div>
        <v-expansion-panels>
            <v-expansion-panel @click="onExpansionPanelClick1">
                <v-expansion-panel-header>Offline Detection Params   </v-expansion-panel-header>
                <v-expansion-panel-content>


                    <v-simple-table>

                        <tbody>
                        <tr v-for="item in detection_offline_params" :key="item.name">
                            <td>{{ item.name }}</td>
                            <td> {{ item.value }}</td>
                        </tr>
                        </tbody>

                    </v-simple-table>

                </v-expansion-panel-content>
            </v-expansion-panel>
        </v-expansion-panels>



        <DataSetList type="3" @refresh="refreshParams" ></DataSetList>
        <h3>&nbsp;</h3>


        <v-col class="text-right">

            <v-btn x-small @click="clearConsole">Clear Console</v-btn>
        </v-col>
        <div class="t0"  ref="container">
            <p class="t1" v-html="logs"></p>
        </div>

    </div>
</template>

<script>
    import axios from "axios";
    import {execCmd, generateUUID,asyncExecApiCmd, execApiCmd} from "../../plugins/myutil";
    import DataSetList from "./DataSetList";
    import {config} from "../../plugins/config"

    const MAXLINES=25;


    const SHOW_ALERTS_ON_HMI_off_line="show_alerts_on_hmi_offline_detection_page";


    let my_uuid = generateUUID();
    let s_url =  config.websocketUrl()+ "/console";
  //  let s_url ="ws://" +location.hostname+':'+location.port+"/console";

    export default {
        name: "TabDetection",
        components: {DataSetList},
        props:['global'],
        data: function () {
            return {
                dataset:"",
                ids_mode:"",
                detection_offline_params:[



            ],
                xlogs: ['']
            }
        },

        methods : {

            startDetection() {

                execApiCmd("ids", "start_detection_offline")
            },
            cancelDetection() {
                execApiCmd("ids", "cancel_detection_offline")
            },
            onExpansionPanelClick1(event) {
               // alert('test');
                if(event.currentTarget.classList.contains('v-expansion-panel-header--active')) {
                    console.log("Panel is closing/now closed.")
                } else {
                    console.log("Panel is opening/now open.")
                }
            },
            refreshParams () {
                let _this=this;
                execApiCmd("ids","get_CSL_detection_offline_args",{},
                    function (value) {
                        _this.detection_offline_params=value;

                        if (!value.error) {
                            for (let keyvalue of _this.detection_offline_params) {
                                console.log(keyvalue)
                                console.log("key=" + keyvalue.name.toLowerCase())
                                if (keyvalue.name.toLowerCase() === "dataset") _this.dataset = keyvalue.value;
                                if (keyvalue.name.toLowerCase() === "ids_mode") _this.ids_mode = keyvalue.value;
                                if (keyvalue.name.toLowerCase() === "ids_mode") {
                                    keyvalue.show_always=true;
                                    _this.ids_mode=keyvalue.value;
                                    _this.global.ids_mode=keyvalue.value+ "";
                                }
                            }
                        }
                } );


            },



            scrollToEnd () {
                var content = this.$refs.container;
                content.scrollTop = content.scrollHeight;
            },

            addLine(line) {
                this.xlogs.push(line);
                if (this.xlogs.length>MAXLINES) this.xlogs.shift();
            },


            clearConsole() {
                this.xlogs=[];

            },

            refreshPage() {
                this.refreshParams();
            }
        },

        computed: {


            logs() {
                let s = '';
                //let xlogs = ["line 1", "line 2", "line 3", "line 4"];
                for (let z of this.xlogs) {
                    s = s + z + '<br>'
                }
                return '<pre>' + s + '</pre>';
                //   return "<pre>abc</pre>";
            }
        },


        mounted: function () {
            axios.defaults.headers.common['Access-Control-Allow-Origin'] = '*';
            console.log("Mounting")


            this.refreshParams();

            let webSocket = new WebSocket(s_url);
            let THIS = this;

            console.log(webSocket);
            webSocket.onmessage = function (msg) {
                //console.log("WEBSOCKET");
                //console.log(msg.data);
                let data = JSON.parse(msg.data);
                console.log(data);

                if (data.loginfo) {

                    if (data.loginfo.console_id === "detect_offline")
                        THIS.addLine(data.loginfo.line);


                    if (data.loginfo.refresh_hmi) {
                        THIS.addLine('>');
                        THIS.refreshParams()
                    }
                }
                // this.xlogs.push(data.loginfo.line)
                /*if ('database' in data) {
                    let name=data.database.name;
                    let uuid=data.database.uuid;
                    console.log("modified json file :"+name+"   uuid="+uuid+"  myuuid="+my_uuid);

                }*/

                THIS.scrollToEnd();

                //updateChat(msg);
            };
            webSocket.onclose = function () {
                alert("WebSocket connection closed DetectionTab")
            };
        }
    }
</script>

