            timeConverter(UNIX_timestamp) {
                if (!UNIX_timestamp) return "";
                var a = new Date(UNIX_timestamp);
                var months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
                var year = a.getFullYear();
                var month = months[a.getMonth()];
                var date = a.getDate();
                var hour = a.getHours();
                var min = a.getMinutes();
                var sec = a.getSeconds();
                var time = date + ' ' + month + ' ' + year + ' ' + hour + ':' + min + ':' + sec;
                return time;
            },

            nameToString(item) {
                if (item.type!=="node") return "";
                if (item.name) {
                    if (item.country) return item.name+' '+item.country;
                    return item.name;
                }
                return item.country

            },

            protocolToString(item) {
                if (item.protocol<0) return "";
                if (item.app_protocol) return item.protocol+" "+item.app_protocol;
                return item.protocol

            },
            whichColor(level) {
                console.log("level")
                for (let i in this.types) {
                    if (this.types[i].type.toUpperCase() == level.toUpperCase()) {
                        return this.types[i].color
                    }
                }
                return "#FFFFFF"
            }
