            <v-col class="text-right">

                <br>
                <v-btn x-small @click="refresh">Refresh</v-btn>
            </v-col>
        </div>-->

        <div>
            <br>
            <b>
            {{title}}
            </b>
        </div>

        <v-data-table
                :headers="headers"
                :items="rows"
                :items-per-page="items_per_page"
                hide-default-footer
                dense
        >
          <!--  <template v-slot:item="{ item , index }"> -->
            <template v-slot:item="{ item }">
                <tr v-bind:style="{'background-color':  whichColor(item.risk)}">


                    <td v-if="item.type!=='node' && item.port_src>=0">{{item.ip_src}}:{{item.port_src}}</td>
                    <td v-if="item.type!=='node' && item.port_src<0">{{item.ip_src}}</td>
                    <td v-if="item.type==='node'"><b>{{item.ip_src}}</b></td>


                    <td >{{ nameToString(item)}}</td>

                    <td v-if="item.type!=='node'">{{item.addr}}</td><td v-else></td>
                    <td v-if="item.type!=='node'">{{item.fcts }}</td><td v-else></td>
                    <td v-if="item.type!=='node'">{{(item.min) }} {{(item.packets) }}</td><td v-else></td>
                    <td v-if="item.type!=='node'">{{(item.max) }} {{(item.packets) }}</td><td v-else></td>

                    <td v-if="item.type!=='node' && item.port_dst>=0">{{item.ip_dst}}:{{item.port_dst}}</td>
                    <td v-if="item.type!=='node' && item.port_dst<0">{{item.ip_dst}}</td>
                    <td v-if="item.type==='node'"></td>


                    <td v-if="item.type!=='node'">{{item.likelihood}}</td><td v-else>{{item.likelihood}}</td>
                    <td v-if="item.type!=='node'">{{item.severity}}</td><td v-else>{{item.severity}}</td>
                    <td >{{item.risk}}</td>

                    <td v-if="item.type!=='node'">{{protocolToString(item)}}</td><td v-else></td>



                </tr>
            </template>
        </v-data-table>

    </div>

</template>

<script>
    import {execApiCmd} from "@/plugins/myutil";

    const MAX_LEN = 100;

    export default {
        name: 'app',

        props: ['rows','title'],

        data() {
            return {
                overlay: false,
                absolute: true,
                opacity: 0.3,

                search: '',
                items_per_page:-1,
                headers: [
                    {text: 'SRC', sortable: true, value: 'level', width: "7%"},

                    {text: 'Name',sortable:false},
                    {text: '@addr',sortable:false},
                    {text: 'Functions',sortable:false},
                    {text: 'Min',sortable:false},
                    {text: 'Max',sortable:false},

                    {text: 'DST',sortable:false},
                    {text: 'L',sortable:false},
                    {text: 'S',sortable:false},
                    {text: 'Risk',sortable:false},
                    {text: 'Prot',sortable:false},

                ],

                /*
                	public static String[] LEVEL0=new String[] {"NEGLIGIBLE"};
	public static String[] LEVEL1=new String[] {"LOW"};
	public static String[] LEVEL2=new String[] {"MEDIUM LOW"};
	public static String[] LEVEL3=new String[] {"MEDIUM HIGH"};
	public static String[] LEVEL4=new String[] {"HIGH"};


                 */
                types: [
                    {type: "ERROR", color: "#bb00ff"},
                    {type: "DEBUG", color: "#00ff51"},
                    {type: "INFO", color: "#D3D3D3"},
                    {type: "UNDEF", color: "#D3D3D3"},

                    {type: "WARN", color: "#ff9100"},
                    {type: "HIGH", color: "#ff1100"},
                    {type: "CRITICAL", color: "#FF0000"},

                    {type: "MEDIUM HIGH", color: "#FFBF00"},
                    {type: "MODERATE", color: "#FFFF00"},
                    {type: "MEDIUM LOW", color: "#FFFF00"},

                    {type: "TOLERABLE", color: "#00ff51"},
                    {type: "LOW", color: "#00ff51"},


                ],
                list: []
            }
        },
        methods: {

            refresh() {
                let _this=this;

            },
            timeConverter(UNIX_timestamp) {
                if (!UNIX_timestamp) return "";
                var a = new Date(UNIX_timestamp);
                var months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
                var year = a.getFullYear();
                var month = months[a.getMonth()];
                var date = a.getDate();
                var hour = a.getHours();
                var min = a.getMinutes();
                var sec = a.getSeconds();
                var time = date + ' ' + month + ' ' + year + ' ' + hour + ':' + min + ':' + sec;
                return time;
            },

            nameToString(item) {
                if (item.type!=="node") return "";
                if (item.name) {
                    if (item.country) return item.name+' '+item.country;
                    return item.name;
                }
                return item.country

            },

            protocolToString(item) {
                if (item.protocol<0) return "";
                if (item.app_protocol) return item.protocol+" "+item.app_protocol;
                return item.protocol

            },
            whichColor(level) {
                console.log("level")
                if (typeof level ==='undefined') level='';
                for (let i in this.types) {
                    if (this.types[i].type.toUpperCase() == level.toUpperCase()) {
                        return this.types[i].color
                    }
                }
                return "#FFFFFF"
            }
        },
        mounted() {
            var me = this;

            this.refresh();


        }
    }

</script>

