<template>
    <div>
        <!--
        <div>
            <v-btn @click="refreshParams">Refresh Params</v-btn>
            <v-btn @click="clearConsole">Clear console</v-btn>

        </div>
-->


            <v-col class="text-left">

            <b>
                IDS MODE : {{this.global.ids_mode}}</b>
                <br>

            </v-col>
        <div>
            <v-btn @click="stopIds">Stop</v-btn>
            <v-btn @click="startDetection">Detect</v-btn>
            <v-btn @click="startRecording">Record only</v-btn>


        </div>

        <div ref="container">
            <v-simple-table>
                <tr>
                    <td>
                        <v-checkbox
                                v-model="send_to_browser"
                                :label="`Show packets: ${send_to_browser.toString()}`"
                        ></v-checkbox>
                    </td>
                    <td>
                        <v-checkbox
                                v-model="send_to_console"
                                :label="`Show packets on server: ${send_to_console.toString()}`"
                        ></v-checkbox>
                    </td>
                    <td>
                        <v-checkbox
                                v-model="show_console"
                                :label="`Show Console: ${show_console.toString()}`"
                        ></v-checkbox>
                    </td>



                </tr>
            </v-simple-table>
        </div>
        <v-expansion-panels>
            <v-expansion-panel @click="onExpansionPanelClick1">
                <v-expansion-panel-header>Detection params   </v-expansion-panel-header>
                <v-expansion-panel-content>


                    <v-simple-table>

                        <tbody>
                        <tr v-for="item in running_params" :key="item.name">
                            <td>{{ item.name }}</td>
                            <td> {{ item.value }}</td>
                        </tr>
                        </tbody>

                    </v-simple-table>

                </v-expansion-panel-content>
            </v-expansion-panel>
        </v-expansion-panels>




        <DataSetList type="1" @refresh="refreshParams" ></DataSetList>
        <h3>&nbsp;</h3>


        <v-col v-if="show_console" class="text-right">

            <v-btn x-small @click="clearConsole">Clear Console</v-btn>
        </v-col>
        <div v-if="show_console" class="t0"  ref="container">
            <p class="t1" v-html="logs"></p>
        </div>
      <!--  {{running_params}}
        <br>
        dataset:
        {{dataset}}<br>
        to browser:        {{send_to_browser}}<br>
        to console :{{send_to_console}} -->

        <AlertHelper></AlertHelper>

    </div>
</template>

<script>
    import axios from "axios";
    import {execCmd, generateUUID,asyncExecApiCmd, execApiCmd} from "../../plugins/myutil";
    import DataSetList from "./DataSetList";
    import AlertHelper from "@/components/ids/AlertHelper";
    import {config} from "@/plugins/config";
    const MAXLINES=25;

    const SHOW_CONSOLE_ON_HMI="show_console_on_hmi_recording_page";
    const SHOW_ALERTS_ON_HMI="show_alerts_on_hmi_recording_page";

    let my_uuid = generateUUID();
    //let s_url =
    let s_url =config.websocketUrl() +"/console";
//    "ws://" + "127.0.0.1" + ":" + "8000" + "/console";


    export default {
        name: "TabRecording",
        components: {DataSetList,AlertHelper},
        props:['global'],
        data: function () {
            return {
                dataset:"",
                ids_mode:"",
                logToFile:true,
                logToBrowser:true,
                send_to_console:'',
                send_to_browser:'',
                show_console:true,
                show_alerts:true,


                running_params:[
                    {
                        name: 'Start Taps',

                        value:'click',

                    },
                    {
                        name: 'Stop Taps',

                        value:''

                    }


                ],
                xlogs: ['>']
            }
        },

        methods : {

            /*
             <v-btn @click="stopIds">Stop</v-btn>
            <v-btn @click="startDetection">Detect</v-btn>
            <v-btn @click="startRecording">Record only</v-btn>
            <v-btn @click="switchLogToFile">Log to file: {{logToFile}}</v-btn>
            <v-btn @click="switchLogToBrowser">Log to browser: {{logToBrowser}}</v-btn>

             */
            stopIds() {
                execApiCmd("ids", "set_idle_mode")
                //alert('stop')
                this.refreshParams ()
            },
            startDetection() {
                execApiCmd("ids", "start_detection")
                this.refreshParams ()
            },
            startRecording() {
                execApiCmd("ids", "start_recording_only")
                this.refreshParams ()
            },
            updateOnServerSendToBrowser() {
                execApiCmd("ids", "set_send_to_browser",{value:this.send_to_browser})
            },
            updateOnServerSendToConsole() {
                execApiCmd("ids", "set_send_to_console",{value:this.send_to_console})
            },
            updateOnServerShowConsole() {
                execApiCmd("ids", "set_param_boolean",{name:SHOW_CONSOLE_ON_HMI, value:this.show_console})
            },
            updateOnServerShowAlerts() {
                execApiCmd("ids", "set_param_boolean",{name:SHOW_ALERTS_ON_HMI,value:this.show_alerts})
            },



            onExpansionPanelClick1(event) {
                // alert('test');
                this.refreshParams();
                if(event.currentTarget.classList.contains('v-expansion-panel-header--active')) {
                    console.log("Panel is closing/now closed.")
                } else {
                    console.log("Panel is opening/now open.")
                }
            },
            refreshParams () {
                let _this=this;
                execApiCmd("ids","get_CSL_running_args",{},
                    function (value) {
                        _this.running_params=value;
                        for (let keyvalue of _this.running_params) {
                            console.log(keyvalue)
                            console.log("key="+keyvalue.name.toLowerCase())
                            if (keyvalue.name.toLowerCase()==="dataset") _this.dataset=keyvalue.value;
                            if (keyvalue.name.toLowerCase() === "ids_mode") {
                                keyvalue.show_always=true;
                                _this.ids_mode=keyvalue.value;
                                _this.global.ids_mode=keyvalue.value+ "";
                            }

                        }

                    } );

                execApiCmd("ids","get_send_to_console",{},
                    function (x) {
                        if (typeof x.value!== "undefined")
                            _this.send_to_console=x.value;
                        else
                            _this.send_to_console=x;
                    } );

                execApiCmd("ids","get_send_to_browser",{},
                    function (x) {
                        if (typeof x.value!== "undefined")
                            _this.send_to_browser=x.value;


                    } );

                execApiCmd("ids","get_param_boolean",{name:SHOW_ALERTS_ON_HMI},
                    function (x) {
                        if (typeof x.value!== "undefined")
                            _this.show_alerts=x.value;


                    } );

                execApiCmd("ids","get_param_boolean",{name:SHOW_CONSOLE_ON_HMI},
                    function (x) {
                        if (typeof x.value!== "undefined")
                            _this.show_console=x.value;


                    } );
            },



            scrollToEnd () {
                var content = this.$refs.container;
                content.scrollTop = content.scrollHeight;
            },

            addLine(line) {
                this.xlogs.push(line);
                if (this.xlogs.length>MAXLINES) this.xlogs.shift();
            },


            clearConsole() {
                this.xlogs=[];

            },
        },
        watch: {
            send_to_console: function(val) {
                this.updateOnServerSendToConsole()
            },
            send_to_browser: function(val) {
                this.updateOnServerSendToBrowser()
            },
            show_alerts: function(val) {
                this.updateOnServerShowAlerts();
            },
            show_console: function(val) {
                this.updateOnServerShowConsole();
            }
        },
        computed: {
            send_to_browser2: {
              get() {
                  return this.send_to_browser;
              },
              set(value) {
                  this.send_to_browser=value;
                  this.updateOnServerSendToBrowser();
                  alert("ok");
              }
            },

            logs() {
                let s = '';
                //let xlogs = ["line 1", "line 2", "line 3", "line 4"];
                for (let z of this.xlogs) {
                    s = s + z + '<br>'
                }
                return '<pre>' + s + '</pre>';
                //   return "<pre>abc</pre>";
            }
        },


        mounted: function () {
            axios.defaults.headers.common['Access-Control-Allow-Origin'] = '*';
            console.log("Mounting")


            this.refreshParams();
            //let s_url = "ws://" + "127.0.0.1" + ":" + "8000" + "/console";

            let webSocket = new WebSocket(s_url);
            let THIS = this;

            console.log(webSocket);
            webSocket.onmessage = function (msg) {
  //              console.log("WEBSOCKET");
  //              console.log(msg.data);
                let data = JSON.parse(msg.data);
                console.log(data);

                if (data.loginfo) {

                    if (data.loginfo.console_id==="detect_online")
                        THIS.addLine(data.loginfo.line);
                }

                if (data.loginfo&&THIS.send_to_browser) {
                    if (data.loginfo.type==="packet")
                        THIS.addLine('PACKET:'+data.loginfo.line);
                }

                if (data.loginfo.refresh_hmi) {
                    THIS.addLine('>');
                    THIS.refreshParams()
                }

                // this.xlogs.push(data.loginfo.line)
                /*if ('database' in data) {
                    let name=data.database.name;
                    let uuid=data.database.uuid;
                    console.log("modified json file :"+name+"   uuid="+uuid+"  myuuid="+my_uuid);

                }*/

                THIS.scrollToEnd();

                //updateChat(msg);
            };
            webSocket.onclose = function () {
               // alert("WebSocket connection closed RecordingTab")
            };
        }
    }
</script>

<style scoped>

    p {
        padding: 0;
        margin: 5px;
        color: black;
    }

    h3 {
        padding: 0;
        margin-top: 015px;
        color: red;
    }

    .t1 {
        font-weight: bold;
        font-size: 14px;
        line-height: 14px;
        color: white;
        text-align: left;
        min-height: 100px;
    }

    .t0 {
        max-height: 580px;
        background: rgb(3, 9, 36);
        overflow: auto;
    }

    pre {
        font-family: Monaco, Menlo, Consolas, monospace;
        white-space: pre-wrap;
    }
</style>