export * from './tags-mutations';
export * from './tags-actions';


export const store = new Vuex.Store({
    state: {
        count: 0
    },
    mutations: {
        [tags_mutations.INCREMENT] (state) {
            state.count++
        },
        [tags_mutations.DECREMENT] (state) {
            state.count--
        }
    },

    actions :{
        [tags_actions.INIT_STORE] (commit) {
            console.log('INIT')
            //commit(tags_mutations.INCREMENT);
            console.log(commit)
        }

    }
})

