export default function(ipString) {
    let ipArray = ipString.split('.')
    if (ipArray.length != 4) {
        return false
    }
    for(let field of ipArray) {
        let valField = Number.parseInt(field)
        if(Number.isNaN(valField) || valField > 255) {
            return false
        }
    }
    return true
}