<template>

    <v-expansion-panels>
        <v-expansion-panel @click="onExpansionPanelClick1">
            <v-expansion-panel-header>Selected dataset : {{selectedName}}</v-expansion-panel-header>
            <v-expansion-panel-content>
                <v-btn @click="updateList">Update</v-btn>
               <!-- edit:{{editNameFlag}} newname:{{newName}} selected:{{selectedName}}-->
                <v-btn @click="create">Create</v-btn>
                <v-simple-table dense>
                    <template v-slot:default>
                        <thead>&nbsp;

                        <tr>
                            <th class="text-left" width="70%">Name</th>
                            <th class="text-left">Actions</th>

                        </tr>
                        </thead>
                        <tbody>
                        <tr :key="item.name" v-for="item in items">
                            <td v-bind:class="getClass(item)" v-if="!display(item)">{{ item.name }}</td>
                            <td v-bind:class="getClass(item)" v-if="display(item)&&!editNameFlag">{{ item.name }}</td>
                            <td v-if="display(item)&&editNameFlag">
                                    <v-text-field
                                        hint="Enter new name"

                                        v-model="newName"

                                ></v-text-field>
                                <v-btn @click="validate" x-small>Validate</v-btn>
                            </td>

                            <td>
                                <v-btn @click="selectLine(item.name)" class="text-xs-center" v-if="item.folder" x-small>
                                    Select
                                </v-btn>
                                <v-btn @click="showDetails(item.name)" v-if="display(item)" x-small> {{showButtonText}}</v-btn>
                                <v-btn @click="switchEditNameFlag(!editNameFlag)" v-if="display(item)" x-small>
                                    {{editButtonText}}
                                </v-btn>
                            </td>


                            <!-- <td><v-radio-group
                                     v-model="item.option"
                                     row
                             >
                                 <v-radio
                                         label="Option 1"
                                         value="radio-1"
                                 ></v-radio>
                                 <v-radio
                                         label="Option 2"
                                         value="radio-2"
                                 ></v-radio>
                             </v-radio-group></td> -->

                        </tr>
                        </tbody>
                    </template>
                </v-simple-table>


            </v-expansion-panel-content>
        </v-expansion-panel>
    </v-expansion-panels>

</template>

<script>

    import {getDataSetList, opDataSet} from "@/components/ids/idsutil";

    export default {
        name: "DataSetList",

        props: ['type'],
        data: () => ({
            editNameFlag: false,
            editButtonText: "Edit",
            newName: "",


            dense: true,
            showFullPath: true,

            dir: "",
            fixedHeader: false,
            height: 300,
            selectedName: "",
            showButtonText: "Show",

            showFiles: false,
            dataset_files: [],
            datasets: [
                {
                    name: 'Invalid connection',

                    folder: true,
                },

            ],
            items: [
                {
                    name: 'Invalid connection',

                    folder: true,
                },
            ],
        }),
        methods: {
            create() {
                let _this=this;
                opDataSet("create", this.type, "").then(
                    function (value) {
                        _this.updateList();
                    });

            },
            validate() {
                let _this=this;
                opDataSet("rename", this.type, this.selectedName,this.type,this.newName).then(
                    function (value) {
                        _this.updateList();
                    });
            },
            onExpansionPanelClick1() {
              this.updateList();
            },

            switchEditNameFlag(b) {
                this.editNameFlag = b;
                if (b) this.editButtonText = 'Close Edit'
                if (!b) this.editButtonText = 'Edit'
                this.newName = this.selectedName;

            },

            updateName() {
                let _this=this;
          /*      opDataSet("list", 1, name).then(
                    function (value) {
                        _this.updateList();
                    }
                    );*/
            },
            setShowFullpath(b) {
                this.showFullPath = b;
            },
            getClass(item) {
                console.log('getclass');
                console.log(item)
                if (item.folder) return "pl-4";
                return "pl-12";
            },
            selectLine(name) {
                let _this = this;
                //alert(name+' is selected');
                //this.selectedName = name;
                    this.hideDetails();

                this.switchEditNameFlag(false);


 /*               opDataSet("list", 1, name).then(
                    function (value) {
                        _this.dataset_files = value.data;
                        console.log('getDataSet Details resolved');
                        console.log(value);
                    });

*/
                opDataSet("select", this.type, name).then(
                    function (value) {
                        _this.updateList();


                    });


            },
            showDetails(name) {

                if (this.showButtonText !== 'Hide') {
                    this.showButtonText = "Hide";
                    this.showFiles = true;
                } else {
                    this.showButtonText = "Show";
                    this.showFiles = false;
                }
                this.refreshItems();
            },
            hideDetails() {
                this.showButtonText = "Show";
                this.showFiles = false;
                this.refreshItems();
            },
            display(item) {
                if (!item.folder) return false;
                if (item.name === this.selectedName) return true;
                return false;
            },
            async updateList() {
                let _this = this;


                //_this.datasets = await getDataSetList(this.type).value;

                getDataSetList(this.type).then(
                    function (value) {
                        _this.datasets = value.data;
                        _this.refreshItems();
                        console.log('getDataSetList resolved');
                        console.log(value);
                        _this.$emit('refresh')
                    }).error(
                        function(e) {
                            //alert(e)
                            console.log("error")
                        });




            },

            refreshItems() {
                let list = [];
                for (let x of this.datasets) {
                    x.folder = true;
                    if (x.selected) this.selectedName=x.name;
                    list.push(x)
                    if ((x.name === this.selectedName) && this.showFiles) {
                        if (x.files) {
                        for (let f of x.files) {
                            let d = {name: '       ' + f.name, folder: false}
                            list.push(d);
                        }
                    }
                    }
                }
                this.items = list;
            }
        },
        mounted: function () {

            let _this = this;

            this.updateList();
           // this.selectLine(this.dataset);

        }
    }
</script>

<style scoped>

    .v-btn {

        min-width: 36px;
        font-size: 12px;
        padding: 2px;
    }

</style>