export async function asyncExecApiCmd(api,cmd, params) {

    try {
        // fetch data from a url endpoint
        const data = await axios.post(config.apiUrl+'/'+api, {
            cmd: cmd,
            params: params
        });
        return data;
    } catch (error) {
        console.log("asyncExecCmd error", error);
        // appropriately handle the error
        throw  new Error(error)
    }
}

export function execApiCmd(api, cmd,params,setter=null) {

    axios.post(config.apiUrl+'/'+api, {
        cmd: cmd,
        params: params
    })
        .then((response) => {
            console.log("execApiCmd:"+api+" cmd:"+cmd)
            console.log(response.data);
            if (setter) setter(response.data);

        }, (error) => {
            console.log(error);
        });

}


