    <v-row >

      <v-col cols="auto" color="primary lighten-3">
        <v-tabs
          v-model="tab"
           :background-color="activeTab === highlightTab ? 'primary lighten-3' : ''"

        >
          <v-tabs-slider color="primary lighten-3"></v-tabs-slider>
          <v-tab>Active alerts</v-tab>
          <v-tab>Other alerts</v-tab>
        </v-tabs>
      </v-col>
      <v-col>
        <v-btn @click="deleteAlerts()" color="grey " v-bind="attrs" v-on="on" large  >
          <v-icon class="mr-3 ml-n2">
            mdi-delete
          </v-icon>
          Delete alerts
        </v-btn>
      </v-col>
    </v-row>


    <v-tabs-items v-model="tab" >
      <v-tab-item>
        <v-data-table
          :headers="headers"
          :items="list"
          :search="search"
          :items-per-page=20
          dense
          class="primary lighten-3"
        >
          <template  slot="item" slot-scope="props" >
            <tr>
              <td v-if="isLarge">
                <v-tooltip open-delay=500 bottom>
                    <template v-slot:activator="{on, attrs}">
                        <v-btn @click="maskAlert(props.item.uuid)" color="blue-grey lighten-4" v-bind="attrs" v-on="on" x-small class="mr-1" >
                          <v-icon
                            small
                          >
                            mdi-eye-off
                          </v-icon>
                        </v-btn>
                    </template>
                    <span>Mask alert</span>
                </v-tooltip>
                <v-tooltip open-delay=500 bottom>
                    <template v-slot:activator="{on, attrs}">
                        <v-btn @click="addAlertToModel(props.item.uuid,1)" color="yellow lighten-2" v-bind="attrs" v-on="on" x-small class="mr-1">
