                    </template>
                    <span>Add alert to model with level 1</span>
                </v-tooltip>
                <v-tooltip open-delay=500 bottom>
                    <template v-slot:activator="{on, attrs}">
                        <v-btn @click="addAlertToModel(props.item.uuid,2)" color="orange lighten-2" v-bind="attrs" v-on="on" x-small class="mr-1">
                          <v-icon
                            small
                          >
                            mdi-plus-thick
                          </v-icon>
                        </v-btn>
                    </template>
                    <span>Add alert to model with level 2</span>
                </v-tooltip>
                <v-tooltip open-delay=500 bottom>
                    <template v-slot:activator="{on, attrs}">
                        <v-btn @click="addAlertToModel(props.item.uuid,3)" color="orange" v-bind="attrs" v-on="on" x-small class="mr-1">
                          <v-icon
                            small
                          >
                            mdi-plus-thick
                          </v-icon>
                        </v-btn>
                    </template>
                    <span>Add alert to model with level 3</span>
                </v-tooltip>
                <v-tooltip open-delay=500 bottom>
                    <template v-slot:activator="{on, attrs}">
                        <v-btn @click="addAlertToModel(props.item.uuid,4)" color="red lighten-2" v-bind="attrs" v-on="on" x-small class="mr-n16">
                          <v-icon
                            small
                          >
                            mdi-plus-thick
                          </v-icon>
                        </v-btn>
                    </template>
                    <span>Add alert to model with level 4</span>
                </v-tooltip>
              </td>

              <td >
                <v-chip
                  :color="whichColor(props.item.level)"
                  dark
                  small
                >
                  {{ props.item.level }}
                </v-chip>
              </td>
              <td>{{ timeConverter(props.item.timeStamp) }}</td>
              <td>{{ props.item.message }}</td>
            </tr>
          </template>

        </v-data-table>
      </v-tab-item>
      <v-tab-item>
        <v-data-table
          :headers="headersOther"
