          <template  slot="item" slot-scope="props" >
            <tr>
              <td v-if="isLarge">
                <v-tooltip open-delay=500 bottom>
                    <template v-slot:activator="{on, attrs}">
                        <v-btn @click="restoreAlert(props.item)" color="blue-grey lighten-4" v-bind="attrs" v-on="on" x-small class="mr-n16">
                          <v-icon
                            small
                          >
                            mdi-restore
                          </v-icon>
                        </v-btn>
                    </template>
                    <span>Restore alert</span>
                </v-tooltip>

              </td>

