                  :color="whichColor(props.item.level)"
                  dark
                  small
                >
                  {{ props.item.level }}
                </v-chip>
              </td>
              <td>{{ timeConverter(props.item.timeStamp) }}</td>
              <td>{{ props.item.message }}</td>
              <td> <v-simple-checkbox :ripple="false" :value="props.item.added_to_model"  label="red darken-3" > </v-simple-checkbox> <div class='mt-n6 ml-7' v-if="props.item.added_to_model">( Level {{props.item.model_level}} )</div></td>
              <td><v-simple-checkbox :ripple="false" :value="props.item.masked"> </v-simple-checkbox></td>

            </tr>
          </template>

        </v-data-table>      </v-tab-item>
    </v-tabs-items>
  </v-main>

</template>

<script>
    import {execApiCmd} from "@/plugins/myutil";
    import {config} from "@/plugins/config";
    const MAX_LEN = 100;
   // var i = 0;
    export default {
        name: 'app',
        data() {
          return {
            tab:null,
            overlay: false,
            search: '',
            types: [
              { type: "ERROR", color:"#bb00ff" },
              { type: "DEBUG", color:"#00ff51" },
              { type: "INFO", color:"#00ff51" },
              { type: "WARN", color:"#ff9100" },
              { type: "FATAL", color:"#ff1100" },
              { type: "CRITICAL", color:"#ff1100" },
              { type: "UNDEF", color:"#00ff00" },
              { type: "MODERATE", color:"#ff9100" },

            ],
            list: [],
            listOther: [],
          }
        },
        methods: {
          deleteAlerts(){
            this.list = []
            this.listOther = []
            execApiCmd("ids","op_alert",{'op':'reset_list'}, () => {
              this.refreshAlerts();
            });
          },
          refreshAlerts() {
              let _this=this;
              execApiCmd("ids","get_alerts_list",{'op':'get_list_active'},
                  function (value) {
                      _this.list = []
                      for (let i = value.length-1; i >= 0; i--) {
                        _this.list.push(value[i])
                      }
                  }
              );
              execApiCmd("ids","op_alert",{'op':'get_list_all'},
                  function (value) {
                      _this.listOther = []
                      for (let i = value.length-1; i >= 0; i--) {
                        if(value[i].added_to_model || value[i].masked)
                        _this.listOther.push(value[i])
                      }
                  }
              );

          },
          timeConverter(UNIX_timestamp) {
              var a = new Date(UNIX_timestamp);
              var months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
              var year = a.getFullYear();
              var month = months[a.getMonth()];
              var date = a.getDate();
              var hour = a.getHours();
              var min = a.getMinutes();
              var sec = a.getSeconds();
              var time = date + ' ' + month + ' ' + year + ' ' + hour + ':' + min + ':' + sec;
              return time;
          },
          maskAlert(id){
            console.log("masking "+id)
              let me = this
              execApiCmd("ids","op_alert",{'op':'set_masked', 'alert_id':id, 'value':true},
                  function () {
                    me.refreshAlerts()
                  }
              );
          },
          addAlertToModel(id,level){
            console.log("adding "+id+" with level "+level)
              let me = this
              execApiCmd("ids","op_alert",{'op':'add_to_model', 'alert_id':id, 'level':level},
                  function () {
                    me.refreshAlerts()
                  }
              );
          },
          restoreAlert(alert){
              let me = this
              console.log("la")
              console.log(alert)
              if(alert.masked){
                execApiCmd("ids","op_alert",{'op':'set_masked', 'alert_id':alert.uuid, 'value':false},
                    function () {
                      me.refreshAlerts()
                    }
                );
              }
              if(alert.added_to_model){
                 execApiCmd("ids","op_alert",{'op':'remove_from_model', 'alert_id':alert.uuid, 'level':alert.model_level},
                    function () {
                      me.refreshAlerts()
                    }
                );
              }
          },
          updateChat(msg) {
              var data = JSON.parse(msg.data);
              var alert = data.alert;
              if (alert) {
                  let alertInfo = alert.alertInfo;
                  if (this.list.length > MAX_LEN) this.list.shift();
                  this.list.push(alertInfo);
              }
              /*var data = JSON.parse(msg.data);
              var value=data.userMessage;
              if(i < 8000){
                  this.list.unshift(JSON.parse(value));
              }else{
                  this.list.pop();
                  this.list.unshift(JSON.parse(value));
              }
              i++;*/
          },
          whichColor(level){
            for(var i in this.types){
              if( level != null && this.types[i].type.toUpperCase() == level.toUpperCase()){
                return this.types[i].color
              }
            }
            return "#FFFFFF"
          }
        },
      mounted() {
            var me = this;
            this.refreshAlerts();
            console.log('Connect to websocket :alerts');
            let s_url =config.websocketUrl() +"/alerts";
            let webSocket = new WebSocket(s_url);
            webSocket.onmessage = function (msg) {
                me.updateChat(msg);
            };

      },
      computed: {
        headers(){
            console.log(this.isLarge)
            if(this.isLarge){
              return [
                { text:'Actions', sortable:false},
                { text:'Level', sortable:true, value:'level' },
                { text:'TimeStamp', value:'timeStamp',sortable:true },
                { text:'Message', value:'message',sortable:true },
              ];
            }else{
              console.log("not large!")
              return [
                { text:'Level', sortable:true, value:'level' },
                { text:'TimeStamp', value:'timeStamp',sortable:true, width: "24%"},
                { text:'Message', value:'message',sortable:true },
                ];
            }
        },
        headersOther(){
            console.log(this.isLarge)
            if(this.isLarge){
              return [
                { text:'Actions', sortable:false},
                { text:'Level', sortable:true, value:'level' },
                { text:'TimeStamp', value:'timeStamp',sortable:true },
                { text:'Message', value:'message',sortable:true },
                { text:'Added to model', value:'added_to_model',sortable:true },
                { text:'masked', value:'masked',sortable:true },

              ];
            }else{
              return [
                { text:'Level', sortable:true, value:'level' },
                { text:'TimeStamp', value:'timeStamp',sortable:true, width: "24%"},
                { text:'Message', value:'message',sortable:true },
                ];
            }
        }
      },
      props:{
        isLarge:{
          type:Boolean ,
          default:true
        }
      }
    }

</script>

